return items.map(item => {

    // -------- 1. ORIGEN DE DATOS --------
    const rawSummary_A  = item.json.NOMBRE;
    const rawFecha_A    = item.json.FECHA;
    const rawCorreo_A   = item.json.CORREO;
    const rawServicio_A = item.json.SERVICIO;
    const rawTelefono   = item.json.TELEFONO;

    const rawSummary_B  = item.json.summary;
    const rawFecha_B    = item.json.start?.dateTime;
    const rawCorreo_B   = item.json.creator?.email;

    const rawSummary = rawSummary_A || rawSummary_B || "";
    const rawFecha   = rawFecha_A   || rawFecha_B   || "";
    const rawCorreo  = rawCorreo_A  || rawCorreo_B  || "";

    // -------- 2. LIMPIEZA --------
    const clean = t => (t || "")
        .replace(/[\r\n\t]+/g, " ")
        .replace(/\s+/g, " ")
        .trim();

    const summary = clean(rawSummary);

    // -------- 3. CLIENTE Y SERVICIO --------
    let cliente  = "";
    let servicio = "";

    if (rawServicio_A) {
        cliente  = clean(rawSummary_A);
        servicio = clean(rawServicio_A);
    } else {
        let matchA = summary.match(/cita con (.+?) para (.+)$/i);
        let matchB = summary.match(/(.+?)\s+—\s+(.+)/);

        if (matchA) {
            cliente  = matchA[1].trim();
            servicio = matchA[2].trim();
        } else if (matchB) {
            cliente  = matchB[1].trim();
            servicio = matchB[2].trim();
        }
    }

    // -------- 4. NOMBRE + APELLIDO --------
    let nombre = "";
    let apellido = "";
    let nombreCompleto = "";

    if (cliente) {
        const partes = cliente.split(" ").filter(Boolean);

        if (partes[0]) {
            nombre = partes[0][0].toUpperCase() + partes[0].slice(1).toLowerCase();
        }
        if (partes[1]) {
            apellido = partes[1][0].toUpperCase() + partes[1].slice(1).toLowerCase();
        }

        nombreCompleto = apellido ? `${nombre} ${apellido}` : nombre;
    }

    // -------- 5. CAPITALIZAR SERVICIO --------
    const capitalizar = txt =>
        (txt || "")
            .split(" ")
            .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
            .join(" ");

    const servicioCapitalizado = capitalizar(servicio);

    // -------- 6. FECHA / HORA (Europe/Madrid) --------
    let fecha            = "";
    let hora             = "";
    let sheets_fecha     = "";
    let sheets_hora      = "";
    let sheets_fecha_fin = "";
    let sheets_hora_fin  = "";

    if (rawFecha) {
        const d = new Date(rawFecha);

        if (!isNaN(d.getTime())) {

            fecha = new Intl.DateTimeFormat("es-ES", {
                day: "2-digit",
                month: "2-digit",
                year: "numeric",
                timeZone: "Europe/Madrid",
            }).format(d);

            hora = new Intl.DateTimeFormat("es-ES", {
                hour: "2-digit",
                minute: "2-digit",
                hour12: false,
                timeZone: "Europe/Madrid",
            }).format(d);

            const startLocalParts = new Intl.DateTimeFormat("en-GB", {
                year: "numeric",
                month: "2-digit",
                day: "2-digit",
                hour: "2-digit",
                minute: "2-digit",
                hour12: false,
                timeZone: "Europe/Madrid",
            }).formatToParts(d);

            const get = t => startLocalParts.find(p => p.type === t)?.value;
            const pad = n => String(n).padStart(2, "0");

            const sy  = get("year");
            const sm  = get("month");
            const sd  = get("day");
            const sh  = get("hour");
            const smi = get("minute");

            if (sy && sm && sd && sh && smi) {
                sheets_fecha = `${sd}/${sm}/${sy}`;
                sheets_hora  = `${sh}:${smi}`;

                const endDate = new Date(`${sy}-${sm}-${sd}T${sh}:${smi}:00`);
                endDate.setMinutes(endDate.getMinutes() + 60);

                sheets_fecha_fin = `${pad(endDate.getDate())}/${pad(endDate.getMonth()+1)}/${endDate.getFullYear()}`;
                sheets_hora_fin  = `${pad(endDate.getHours())}:${pad(endDate.getMinutes())}`;
            }
        }
    }

    // -------- 7. SALIDA --------
    item.json.nombre           = nombre;
    item.json.apellido         = apellido;
    item.json.nombreCompleto   = nombreCompleto;
    item.json.servicio         = servicioCapitalizado;
    item.json.fecha            = fecha;
    item.json.hora             = hora;
    item.json.correo           = rawCorreo;
    item.json.telefono         = rawTelefono || "";
    item.json.sheets_fecha     = sheets_fecha;
    item.json.sheets_hora      = sheets_hora;
    item.json.sheets_fecha_fin = sheets_fecha_fin;
    item.json.sheets_hora_fin  = sheets_hora_fin;

    return item;
});

